package datastructure.queue;

import datastructure.interfaces.Queue;

/**
 * @description A Queue implementation backed by a circular fixed-size array.
 * @usage Useful for First-In-First-Out (FIFO) processing when the maximum capacity is known in advance and high performance with O(1) enqueue/dequeue is desired.
 * @summary Implements the Queue interface using a circular array technique. Maintains 'front' and 'size' pointers to handle wrap-around indices efficiently without shifting elements.
 */
public class ArrayQueue<T> implements Queue<T> {

    private final T[] data;
    private final int capacity;
    private int front;
    private int size;

    public ArrayQueue() {
        this(10000);
    }

    @SuppressWarnings("unchecked")
    public ArrayQueue(int capacity) {
        this.capacity = capacity;
        this.data = (T[]) new Object[capacity];
        this.front = 0;
        this.size = 0;
    }

    @Override
    public void enQueue(T item) {
        if (size == capacity) {
            throw new IllegalStateException("Queue is full");
        }
        int end = (front + size) % capacity;
        data[end] = item;
        size++;
    }

    @Override
    public T deQueue() {
        if (size == 0) {
            return null;
        }
        var item = data[front];
        data[front] = null;
        front = (front + 1) % capacity;
        size--;
        return item;
    }

    @Override
    public T peek() {
        return size == 0 ? null : data[front];
    }

    @Override
    public boolean contains(T item) {
        for (int i = 0; i < size; i++) {
            if (data[(front + i) % capacity].equals(item)) {
                return true;
            }
        }
        return false;
    }

    @Override
    public T get(int position) {
        if (position < 0 || position >= size) {
            return null;
        }
        return data[(front + position) % capacity];
    }

    @Override
    public int size() {
        return size;
    }

    @Override
    public boolean isEmpty() {
        return size == 0;
    }
}

package datastructure.stack;

import datastructure.interfaces.Stack;

/**
 * @description A Stack implementation backed by a fixed-size array.
 * @usage Ideal for Last-In-First-Out (LIFO) processing when the maximum number of elements is known beforehand, ensuring low memory overhead and strict O(1) performance.
 * @summary Implements the Stack interface using an array and a pointer indicating the top. Elements are pushed by incrementing the pointer and popped by decrementing it.
 */
public class ArrayStack<T> implements Stack<T> {
    private final T[] data;
    private final int capacity;
    private int pointer;

    public ArrayStack() {
        this(10000);
    }

    @SuppressWarnings("unchecked")
    public ArrayStack(int capacity) {
        this.capacity = capacity;
        data = (T[]) new Object[capacity];
        pointer = 0;
    }

    @Override
    public void push(T item) {
        if (pointer == capacity) {
            throw new IllegalStateException("Stack is full");
        }
        data[pointer++] = item;
    }

    @Override
    public T pop() {
        if (pointer == 0) {
            return null;
        }
        return data[--pointer];
    }

    @Override
    public T peek() {
        return pointer == 0 ? null : data[pointer - 1];
    }

    @Override
    public boolean contains(T item) {
        for (int i = 0; i < pointer; i++) {
            if (data[i].equals(item)) {
                return true;
            }
        }
        return false;
    }

    @Override
    public T get(T item) {
        for (int i = pointer - 1; i >= 0; i--) {
            if (data[i].equals(item)) {
                return data[i];
            }
        }
        return null;
    }

    @Override
    public int size() {
        return pointer;
    }

    @Override
    public boolean isEmpty() {
        return pointer == 0;
    }
}

package datastructure;

import java.util.ArrayList;
import java.util.List;

/**
 * @description A basic Binary Search Tree (BST) implementation.
 * @usage Useful for maintaining a sorted collection of elements with efficient search, insertion, and deletion operations (O(log n) on average).
 * @summary Implements a node-based binary tree structure. Supports insertion, searching, Hibbard deletion, and in-order traversal.
 */
public class BasicBinaryTree<T extends Comparable<T>> {

    private Node root;
    private int size;

    public BasicBinaryTree() {
        this.root = null;
    }

    public int size() {
        return size;
    }

    public boolean isEmpty() {
        return size == 0;
    }

    public void add(T item) {
        root = insert(root, item);
        size++;
    }

    public boolean contains(T item) {
        return search(root, item) != null;
    }

    // Standard Hibbard deletion: copy the in-order successor's value into the
    // node being removed, then delete the successor (which has at most one
    // child). This avoids manual parent-pointer surgery, which previously
    // could leave a node pointing at itself when the immediate left child had
    // no right subtree.
    public boolean delete(T item) {
        if (search(root, item) == null) {
            return false;
        }
        root = deleteRecursive(root, item);
        size--;
        return true;
    }

    public List<T> inorderTraversal() {
        var result = new ArrayList<T>();
        inorder(root, result);
        return result;
    }

    private Node insert(Node node, T item) {
        if (node == null) {
            return new Node(item);
        }
        if (item.compareTo(node.getItem()) < 0) {
            node.setLeft(insert(node.getLeft(), item));
        } else {
            node.setRight(insert(node.getRight(), item));
        }
        return node;
    }

    private Node search(Node node, T item) {
        if (node == null) {
            return null;
        }
        var comparison = item.compareTo(node.getItem());
        if (comparison == 0) {
            return node;
        }
        return comparison < 0 ? search(node.getLeft(), item) : search(node.getRight(), item);
    }

    private Node deleteRecursive(Node node, T item) {
        var comparison = item.compareTo(node.getItem());
        if (comparison < 0) {
            node.setLeft(deleteRecursive(node.getLeft(), item));
            return node;
        }
        if (comparison > 0) {
            node.setRight(deleteRecursive(node.getRight(), item));
            return node;
        }
        if (node.getLeft() == null) {
            return node.getRight();
        }
        if (node.getRight() == null) {
            return node.getLeft();
        }
        var successor = min(node.getRight());
        node.setItem(successor.getItem());
        node.setRight(deleteMin(node.getRight()));
        return node;
    }

    private Node min(Node node) {
        while (node.getLeft() != null) {
            node = node.getLeft();
        }
        return node;
    }

    private Node deleteMin(Node node) {
        if (node.getLeft() == null) {
            return node.getRight();
        }
        node.setLeft(deleteMin(node.getLeft()));
        return node;
    }

    private void inorder(Node node, List<T> result) {
        if (node == null) {
            return;
        }
        inorder(node.getLeft(), result);
        result.add(node.getItem());
        inorder(node.getRight(), result);
    }

    private class Node {
        private Node left;
        private Node right;
        private T item;

        Node(T item) {
            this.item = item;
        }

        Node getLeft() {
            return left;
        }

        void setLeft(Node left) {
            this.left = left;
        }

        Node getRight() {
            return right;
        }

        void setRight(Node right) {
            this.right = right;
        }

        T getItem() {
            return item;
        }

        void setItem(T item) {
            this.item = item;
        }
    }
}

