/**
 * @description A basic implementation of a Hash Table, providing key-value mapping functionality.
 * @usage Best used when fast O(1) lookups, insertions, and deletions are required, and the exact order of elements is not important.
 * @summary Uses an array of HashEntry objects and implements open-addressing with linear probing to handle collisions. It automatically resizes when a load factor threshold is reached.
 */
public class BasicHashTable<K, V> {
    private static final double LOAD_FACTOR_THRESHOLD = 0.7;

    private HashEntry<K, V>[] data;
    private int capacity;
    private int size;

    public BasicHashTable(int tableSize) {
        this.capacity = tableSize;
        this.data = newTable(tableSize);
        this.size = 0;
    }

    public V get(K key) {
        var hash = calculateHash(key);
        return data[hash] == null ? null : data[hash].value();
    }

    public void put(K key, V value) {
        if ((double) (size + 1) / capacity > LOAD_FACTOR_THRESHOLD) {
            grow();
        }
        var hash = calculateHash(key);
        if (data[hash] == null) {
            size++;
        }
        data[hash] = new HashEntry<>(key, value);
    }

    public V delete(K key) {
        var value = get(key);
        if (value != null) {
            var hash = calculateHash(key);
            data[hash] = null;
            size--;

            // Standard open-addressing shift-delete: pull subsequent entries
            // in the probe chain back so future lookups still find them.
            hash = (hash + 1) % capacity;
            while (data[hash] != null) {
                var entry = data[hash];
                data[hash] = null;
                size--;
                put(entry.key(), entry.value());
                hash = (hash + 1) % capacity;
            }
        }
        return value;
    }

    public boolean hasKey(K key) {
        // calculateHash's probe only ever stops on an empty slot or the
        // matching key, so a non-null slot here is guaranteed to be a match.
        var hash = calculateHash(key);
        return data[hash] != null;
    }

    public boolean hasValue(V value) {
        for (var entry : data) {
            if (entry != null && entry.value().equals(value)) {
                return true;
            }
        }
        return false;
    }

    public int size() {
        return this.size;
    }

    public boolean isEmpty() {
        return size == 0;
    }

    private int calculateHash(K key) {
        var hash = Math.floorMod(key.hashCode(), capacity);
        while (data[hash] != null && !data[hash].key().equals(key)) {
            hash = (hash + 1) % capacity;
        }
        return hash;
    }

    private void grow() {
        var oldData = data;
        capacity *= 2;
        data = newTable(capacity);
        size = 0;
        for (var entry : oldData) {
            if (entry != null) {
                put(entry.key(), entry.value());
            }
        }
    }

    @SuppressWarnings("unchecked")
    private static <K, V> HashEntry<K, V>[] newTable(int capacity) {
        return (HashEntry<K, V>[]) new HashEntry[capacity];
    }

    private record HashEntry<K, V>(K key, V value) {
    }
}

package datastructure;

import datastructure.interfaces.LinkedList;

/**
 * @description A basic singly linked list implementation.
 * @usage Used for collections where frequent dynamic additions and removals (especially at the beginning or end) are needed without the overhead of resizing an underlying array.
 * @summary Composed of Node objects where each node points to the next. Supports standard list operations like add, insert, remove, and find.
 */
public class BasicLinkedList<T> implements LinkedList<T> {

    private Node first;
    private Node last;
    private int nodeCount;

    public BasicLinkedList() {
        first = null;
        last = null;
        nodeCount = 0;
    }

    @Override
    public int size() {
        return nodeCount;
    }

    @Override
    public boolean isEmpty() {
        return nodeCount == 0;
    }

    @Override
    public void add(T item) {
        var itemNode = new Node(item);
        if (nodeCount == 0) {
            first = itemNode;
            last = first;
        } else {
            last.setNextNode(itemNode);
            last = itemNode;
        }
        nodeCount++;
    }

    @Override
    public T remove() {
        if (nodeCount == 0) {
            return null;
        }
        var item = first.getNodeItem();
        first = first.getNextNode();
        nodeCount--;
        if (nodeCount == 0) {
            last = null;
        }
        return item;
    }

    @Override
    public void insert(int position, T item) {
        if (position < 0 || position > nodeCount) {
            throw new IndexOutOfBoundsException("position: " + position + ", size: " + nodeCount);
        }
        if (position == nodeCount) {
            add(item);
            return;
        }
        if (position == 0) {
            var newNode = new Node(item);
            newNode.setNextNode(first);
            first = newNode;
            nodeCount++;
            return;
        }
        var prevNode = nodeAt(position - 1);
        var newNode = new Node(item);
        newNode.setNextNode(prevNode.getNextNode());
        prevNode.setNextNode(newNode);
        nodeCount++;
    }

    @Override
    public T removeAt(int position) {
        if (position < 0 || position >= nodeCount) {
            throw new IndexOutOfBoundsException("position: " + position + ", size: " + nodeCount);
        }
        if (position == 0) {
            return remove();
        }
        var prevNode = nodeAt(position - 1);
        var currentNode = prevNode.getNextNode();
        prevNode.setNextNode(currentNode.getNextNode());
        if (currentNode == last) {
            last = prevNode;
        }
        nodeCount--;
        return currentNode.getNodeItem();
    }

    @Override
    public int find(T item) {
        var currentNode = first;
        for (int i = 0; i < nodeCount; i++) {
            if (currentNode.getNodeItem().equals(item)) {
                return i;
            }
            currentNode = currentNode.getNextNode();
        }
        return -1;
    }

    @Override
    public T get(int position) {
        if (position < 0 || position >= nodeCount) {
            throw new IndexOutOfBoundsException("position: " + position + ", size: " + nodeCount);
        }
        return nodeAt(position).getNodeItem();
    }

    private Node nodeAt(int position) {
        var currentNode = first;
        for (int i = 0; i < position; i++) {
            currentNode = currentNode.getNextNode();
        }
        return currentNode;
    }

    private class Node {
        private Node nextNode;
        private final T nodeItem;

        Node(T item) {
            this.nodeItem = item;
            this.nextNode = null;
        }

        Node getNextNode() {
            return this.nextNode;
        }

        void setNextNode(Node n) {
            this.nextNode = n;
        }

        T getNodeItem() {
            return this.nodeItem;
        }
    }
}

package datastructure.queue;

import datastructure.interfaces.Queue;

import java.util.ArrayList;
import java.util.List;

/**
 * @description A Queue implementation backed by an ArrayList.
 * @usage Ideal for First-In-First-Out (FIFO) processing tasks where simple array-based backing is sufficient, though dequeueing may shift elements.
 * @summary Implements the Queue interface using java.util.ArrayList to store elements. Provides standard enqueue, dequeue, and peek operations.
 */
public class ListQueue<T> implements Queue<T> {

    private final List<T> data;

    public ListQueue() {
        data = new ArrayList<>();
    }

    @Override
    public void enQueue(T item) {
        data.add(item);
    }

    @Override
    public T deQueue() {
        if (data.isEmpty()) {
            return null;
        }
        return data.removeFirst();
    }

    @Override
    public T peek() {
        return data.isEmpty() ? null : data.getFirst();
    }

    @Override
    public boolean contains(T item) {
        return data.contains(item);
    }

    @Override
    public T get(int position) {
        if (position < 0 || position >= data.size()) {
            return null;
        }
        return data.get(position);
    }

    @Override
    public int size() {
        return data.size();
    }

    @Override
    public boolean isEmpty() {
        return data.isEmpty();
    }
}

package datastructure.stack;

import datastructure.interfaces.Stack;

import java.util.ArrayList;
import java.util.List;

/**
 * @description A Stack implementation backed by an ArrayList.
 * @usage Best used for Last-In-First-Out (LIFO) processing such as undo mechanisms or backtracking, where dynamic resizing is needed.
 * @summary Implements the Stack interface using java.util.ArrayList. Elements are pushed and popped from the end of the list for amortized O(1) operations.
 */
public class ListStack<T> implements Stack<T> {
    private final List<T> data;

    public ListStack() {
        data = new ArrayList<>();
    }

    @Override
    public void push(T item) {
        data.add(item);
    }

    @Override
    public T pop() {
        if (data.isEmpty()) {
            return null;
        }
        return data.removeLast();
    }

    @Override
    public T peek() {
        return data.isEmpty() ? null : data.getLast();
    }

    @Override
    public boolean contains(T item) {
        return data.contains(item);
    }

    @Override
    public T get(T item) {
        for (int i = data.size() - 1; i >= 0; i--) {
            if (data.get(i).equals(item)) {
                return data.get(i);
            }
        }
        return null;
    }

    @Override
    public int size() {
        return data.size();
    }

    @Override
    public boolean isEmpty() {
        return data.isEmpty();
    }
}
